code_example_1_basic.code:
#include <iostream>

int main() {
    int health = 80;
    // Declare an integer pointer and initialize it with the address of 'health'
    int* healthPtr = &health;

    std::cout << "[Variable info] health = " << health << "\n";
    std::cout << "[Memory Address] &health = " << &health << "\n";
    std::cout << "[Pointer content] healthPtr = " << healthPtr << "\n";
    std::cout << "[Dereferenced pointer] *healthPtr = " << *healthPtr << "\n\n";

    // Modify value indirectly through the pointer
    *healthPtr = 100;
    std::cout << "[After Modification] health = " << health << "\n";
    std::cout << "[After Modification] *healthPtr = " << *healthPtr << "\n";

    // Create a pointer to nullptr
    int* emptyPtr = nullptr;
    if (emptyPtr == nullptr) {
        std::cout << "[Safety Check] emptyPtr is safe and points to nothing.\n";
    }

    return 0;
}

code_example_2_practical.code:
#include <iostream>
#include <string>

class Character {
public:
    std::string name;
    Character(std::string n) : name(n) {
        std::cout << "[Constructor] Character " << name << " created on Heap.\n";
    }
    ~Character() {
        std::cout << "[Destructor] Character " << name << " destroyed and memory freed.\n";
    }
};

int main() {
    std::cout << "=== 1. Manual Memory Allocation (Old C++ Style) ===\n";
    // Allocating dynamic memory manually on the Heap
    Character* rawPtr = new Character("Geralt");
    std::cout << "Character Name: " << rawPtr->name << "\n";
    // Explicit deallocation is mandatory, or a memory leak occurs
    delete rawPtr;
    rawPtr = nullptr; // Set to nullptr to avoid dangling pointer issues

    std::cout << "\n=== 2. Smart Memory Allocation (Modern C++ Style) ===\n";
    {
        // Allocating dynamic memory with an automatic unique_ptr wrapper
        std::unique_ptr<Character> smartPtr = std::make_unique<Character>("Yennefer");
        std::cout << "Character Name: " << smartPtr->name << "\n";
        // No delete required. Memory will automatically free when the block ends.
    } 
    std::cout << "Scope ended for smartPtr.\n";

    return 0;
}

questions.answer:
The ampersand (&) acts as the 'address-of' operator when placed before an already declared variable. Instead of retrieving the value stored in the variable, it queries the variable's physical hexadecimal memory address. To print the address of an integer named 'level', you can use:

int level = 15;
std::cout << &level << std::endl;

