class SimpleIntOwner {
private:
    int* rawPtr;
public:
    explicit SimpleIntOwner(int* p) : rawPtr(p) {}
    ~SimpleIntOwner() {
        delete rawPtr;
    }
    int getValue() const {
        return rawPtr ? *rawPtr : 0;
    }
    void setValue(int val) {
        if (rawPtr) *rawPtr = val;
    }
    // Prevent copy operations to behave like unique_ptr
    SimpleIntOwner(const SimpleIntOwner&) = delete;
    SimpleIntOwner& operator=(const SimpleIntOwner&) = delete;
};

questions.question:
Given a Node structure containing an integer value and a next pointer, write a function 'appendNode' that appends a new node with value 'val' at the end of a pointer-linked list. It should work even if the list is empty (represented by a head pointer that is nullptr).

struct Node {
    int data;
    Node* next;
};
void appendNode(Node*& head, int val);

questions.answer:
void appendNode(Node*& head, int val) {
    Node* newNode = new Node{val, nullptr};
    if (head == nullptr) {
        head = newNode;
        return;
    }
    Node* current = head;
    while (current->next != nullptr) {
        current = current->next;
    }
    current->next = newNode;
}

